(3,2,NULL,'ERA II 172, 18/9 (3)','ERA, Pl. 19 A1',NULL,'XV 459',1,1,1,NULL,'<Helisalvestus: Selge ja ilus>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,3955),
