(27,2,NULL,'ERA II 115, 244/6 (7)','ERA, Fon. 454 c',NULL,'VII 118',1,1,1,'Tampere ERlV III: 42-44','<Helisalvestus: Arusaadav, noodistus vastab detailides salvestusele.>\n<Kontrollitud: T. O. Kindlasti noodistatud salvestuselt, välitööde noodistust ei ole. Lisasin teksti viite.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4628),
