(30,2,NULL,NULL,'ERA, Pl. 21 B4',NULL,'XV 474',1,1,1,NULL,'<Helisalvestus: Selge ja ilus. Transkriptsioonil viis ja tekst täies pikkuses. \n>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Teksti otsingutest: ERA II 132, 30-67 POLE; 115 (11-23, 113-158) KATKI, VAATAMATA; 102 (36/7) POLE, 23 (259/61) POLE 21.02.2019.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4004),
(31,2,NULL,NULL,'ERA, Pl. 24 A1',NULL,'XV 475',1,1,1,NULL,'<Helisalvestus: Selge ja ilus. Transkriptsioonil viis ja tekst täies pikkuses. \n>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4005),
(32,2,'ERA III 1, 137 (29)','ERA II 21, 195/7 (40)','ERA, Fon. 266 c',NULL,'VIII 159',1,1,1,NULL,'<Helisalvestus: Selge, ilus, tekstist ja noodist veidi erinev variant.>\n<Kontrollitud: T. O. Lisasin teksti viite, esitaja nime ja andmed. Tekst ja heli/noot eri variandid (2 või 3), heli on noodist pikem, aga noodi variatsiooni pole mujal. Noodi ja teksti juures vanad fonogramminumbrid.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,2298),
(33,2,NULL,NULL,'ERA, Pl. 29 A1',NULL,'XV 490',1,1,1,NULL,'<Helisalvestus: Selge ja väga-väga ilus>\n<Kontrollitud: T. O. Tõstsin viisi ja teksti viited originaalide kohalt noodistuste hulka. Noodistuseks märgitud ERA, Pl. 29 A1 on helisalvestuse transkriptsioon, teksti viiteks märgitud RKM III 4, 53/55 (1) on eelneva ümberkirjutus, mille nootides on tehtud mõned vead; teksti on vbl parandatud (ei võrrelnud.) 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4008),
