(285,2,NULL,'ERA II 172, 40 (23)','ERA, Pl. 19 B2',NULL,'XV 463',1,1,1,NULL,'<Helisalvestus: Selge ja ilus>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud teksitga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, hea noodistus, pisikesi ebatäpsusi. Tekst ja heli üsna kattuvad, aga on jäädvustatud eraldi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,3958),
