(287,2,'ERA III 1, 127 (2)','ERA II 21, 155/6','ERA, Fon. 258 a',NULL,'XII 358 / 364',1,1,1,NULL,'<Helisalvestus: Selge, lõpuosas mingi kahjustus. Märgitud: (Fon. N 1 a)>\n<Kontrollitud: T. O. Ilmselt on välitöödel tehtud noodistust hiljem fonogrammi järgi täpsustatud. Lisasin heli viite. Teksti juures on vanad fonogrammi numbrid. Koguja on teksti jaganud a ja b osaks, digiteerija on jaganud ka fonogrammi.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4411),
(288,2,NULL,NULL,'ERA, Pl. 28 A2',NULL,'XV 486',1,1,1,NULL,'<Helisalvestus: Selge ja ilus>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus. Parandasin viisi vormi, laululiigi (oli lüürika). Viis on varieeruv 1-realine, ei kuulu siia tabelisse. 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,4006),
