(292,2,'RKM III 3, 111 (88)',NULL,NULL,NULL,'XI 186',1,1,1,NULL,'<Kontrollitud: T. O. Laulja juures originaalis elukohta ei näe, andmebaasis oli märgitud samuti nagu eelmine kirje, RKM III 3, 108 (75). Oli: Vastseliina?=Rõuge? Ma jätsin praegu nii ja panin Rõuge khk, nagu ka eelmise puhul. Rütmitüüp OK. 1.01.2021>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,3153),
