(1524,2,'ERA III 2, 165 (154)','ERA II 16, 388/9 (21)','ERA, Fon. 232 a',NULL,'II 341',1,1,1,NULL,'<Helisalvestus: Heli ja noot üsna ühed, samade algusvärssidega tekst pikem.>\n<Kontrollitud: T. O Lisasin teksti viite, parandasin esitaja nime (oli Jüri). Noodistusel võib olla kasutatud salvestust.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,400),
(1525,2,'ERA III 2, 209 (194)','ERA II 17, 301 (183/4)','ERA, Fon. 235 a',NULL,'II 376',1,1,1,NULL,'<Helisalvestus: Heli on pikk ja selge, mitukümmend värssi, noodistusel algus ja variatsioonid. Ainult algusvärsi kordusosa on noodis salvestusest erinev - kas eksitus või teine variant. Tagaosa on kindlasti salvestuse järgi noodistatud. Teksti üleskirjutus on salvestusest pikem, olemasolevates osades nad üsna kattuvad.>\n<Kontrollitud: T. O Noodistatud võib olla vähemalt osaliselt salvestuse põhjal, vbl on siiski salvestuse algusvärsi ja teksti aluseks teine variant. Muutsin vormi kuulamise põhjal AA-ks.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,429),
(1526,2,'ERA III 2, 231 (215)','ERA II 17, 332 (208)','ERA, Fon. 239 c',NULL,'II 353',1,1,1,NULL,'<Helisalvestus: Heli on selge, ei kattu noot-noodilt noodistusega.>\n<Kontrollitud: T. O Noodistusel on üks viis (=viisitüüp), mida on salvestatud kahelt eri inimeselt. Tegin salvestustest kaks eri varianti. Noodistus ei vasta täpselt kummalegi, on tõenäoliselt tehtud salvestustest eraldi, vbl kuulates mõlemat lauljat.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,411),
(1527,1,'RKM II 142, 469 (1)',NULL,NULL,NULL,'VI 351',1,1,1,NULL,NULL,NULL,NULL,946),
(1528,2,'ERA III 6, 25 (29)','ERA II 30, 145/6 (2) / ERA III 6, 25 (29)','ERA, Fon. 306 b1',NULL,'II 195',1,1,1,'VK VIII','<Helisalvestus: Selge heli. Füüsiliselt on üks salvestus (306 b) ja üks tekst (145/6 (2), mis ei ole jagatud, kuid nad vastavad kahele eri noodile ERA III 6, 25 (29) ja (30). Siinsele noodile vastab salvestuse ja teksti algusosa.>\n<Kontrollitud: T. O. Lisasin teksti viite, noodistaja ja litereerija andmed oli tabelisse kirjutanud ilmselt Edna Tuvi. Tekst on kirjutatud vähemalt kahe esituse põhjal.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,140),
(1529,2,NULL,'ERA II 56, 271/2 (2)','ERA, Fon. 388 a',NULL,'VII',1,1,1,NULL,'<Helisalvestus: Selge, vastab detailides noodistusele. Laul tervelt noodistatud.>\n<Kontrollitud: T. O. Noodistus tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,1008),
