(1540,2,NULL,'ERA II 172, 28/9 (13)','ERA, Pl. 19 A3',NULL,'XV 461',1,1,1,NULL,'<Helisalvestus: Selge ja ilus>\n<Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile, aga heliga võrreldes väikseid vigu. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Lisasin laulutüübi. Muutsin laululiigi. 21.02.2019>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,3956),
(1541,2,NULL,'ERA II 172, 24/5 (8)','ERA, Pl. 19 A2',NULL,NULL,1,1,1,NULL,'<Helisalvestus: Selge ja ilus>\n<Kontrollitud: Tegin uue kirje, ei näe põhjust, miks see viis on kõrvale jäänud. Noodistuse mustand on arhiivis, puhtand on kartoteegikaart. Noodistus enam-vähem... Tekst ja heli on jäädvustatud eri esituste järgi. T. O. 2019.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,NULL),
