(2883,2,'EÜS IX 1291 (65)','N','ERA, Fon. 009 d',NULL,'XIII 270',1,1,1,NULL,'<Helisalvestus: Helisalvestus selge, vastab esimesele noodistusele.>\n<Kontrollitud: T. O Lisasin heli viite, sellele vastab esimene noodistus. Siin on kaks erinevat noodistust samast värsipaarist. Mõlemad eri rütmiga. 23.02.2021 Täpsustasin rütmitüüpi, oli 13&6. 7.12.2020.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,1346),
