(3922,2,NULL,'ERA II 29, 257/261 (2) / ERA II 29, 266/268 (3)','ERA, Fon. 315 b',NULL,'X 271',1,1,1,NULL,'<Helisalvestus: Arusaadav, vastab noodistusele, tekstist mitu varianti, salvestusel tekst 2b. Noodistus algab salvestuse 2. värsist.>\n<Kontrollitud: T. O. Noodistatud (või kontrollitud) on salvestuse järgi, detailides suur kokkulangevus. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ja pole kõrval nende nimesid. Kirjutasin märkustesse. Parandasin vanus (oli 86). Muutsin rütmitüübi, oli 7.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,3021),
(3923,2,'ERA III 2, 15 (5)','ERA II 17, 91 (43)','ERA, Fon. 211 b',NULL,'X 194',1,1,1,NULL,'<Helisalvestus: Heli 1. värss kattub noodiga, heli on noodistusest pikem, halvasti arusaadav.>\n<Kontrollitud: T. O Ei tea, kas noodistatud on salvestuse põhjal, sest noodistuse teist rida on salvestuselt raske välja kuulda. Tekstiga võrreldes tundub, on salvestusel teine variant.>','31554769-b23b-4e3a-b2be-7320c0b3f523',NULL,2940),
